import{_ as e,c as r,o as a,d as n}from"./app.f1e4bbc1.js";const g='{"title":"\u041D\u0435\u0439\u0440\u043E\u043D","description":"","frontmatter":{"title":"\u041D\u0435\u0439\u0440\u043E\u043D","subtitle":"\u0425\u0430\u043A\u0441\u043F\u0435\u0439\u0441","date":"2015-04-26","icon":"G5xZ4RHik2M.jpg","cover":"IMG_0103.jpg","email":"neuron@hackspace.ru","url":"https://neuronspace.ru","address":"\u0425\u043E\u0445\u043B\u043E\u0432\u0441\u043A\u0438\u0439 \u043F\u0435\u0440., 7/9\u04412","place":"\u043C. \u041A\u0438\u0442\u0430\u0439-\u0433\u043E\u0440\u043E\u0434","city":"\u0433. \u041C\u043E\u0441\u043A\u0432\u0430","tel":"+7 (495) 008-13-37","vk":"neuronspace","youtube-channel":"UCmJNyrEsnoDCJghI-5BXrTw","status":"closed","telegram":"neuronspace","instagram":"neuronspace","facebook":"neuronspace"},"headers":[{"level":2,"title":"\u0414\u043B\u044F \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0445 \u0447\u043B\u0435\u043D\u043E\u0432","slug":"\u0434n\u044F-\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0445-\u0447n\u0435\u043D\u043E\u0432"},{"level":2,"title":"\u0414\u043B\u044F \u0433\u043E\u0441\u0442\u0435\u0439","slug":"\u0434n\u044F-\u0433\u043E\u0441\u0442\u0435\u0439"},{"level":2,"title":"\u041C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F","slug":"\u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F"}],"relativePath":"workshop/archive/hackspace-neuron/index.md"}',t={},l=n('<p>\u0425\u0430\u043A\u0441\u043F\u0435\u0439\u0441 Neuron \u2013 \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u0430\u044F \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u0430\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044F, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u0430\u044F \u0435\u0451 \u0447\u043B\u0435\u043D\u0430\u043C\u0438. \u041F\u0435\u0440\u0432\u044B\u0439 \u0445\u0430\u043A\u0441\u043F\u0435\u0439\u0441 \u0432 \u0420\u043E\u0441\u0441\u0438\u0438, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0441 \u0438\u044E\u043B\u044F 2011 \u0433\u043E\u0434\u0430.</p><p>\u0427\u0442\u043E \u0442\u044B \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0448\u044C, \u043F\u0440\u0438\u0445\u043E\u0434\u044F \u0432 \u0445\u0430\u043A\u0441\u043F\u0435\u0439\u0441 Neuron?</p><ul><li>\u042D\u043B\u0435\u043A\u0442\u0440\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0438 \u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442</li><li>\u041F\u0430\u044F\u043B\u044C\u043D\u043E\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435</li><li>\u0427\u0430\u0439 \u0438 \u043A\u043E\u0444\u0435 (\u0435\u0434\u0430 \u2013 \u0432 \u043A\u0430\u0444\u0435 \u0440\u044F\u0434\u043E\u043C)</li><li>\u0411\u0438\u0431\u043B\u0438\u043E\u0442\u0435\u043A\u0443 \u0445\u0430\u043A\u0441\u043F\u0435\u0439\u0441\u0430</li><li>\u0413\u0438\u043A\u043E\u0432\u0441\u043A\u0443\u044E \u0430\u0442\u043C\u043E\u0441\u0444\u0435\u0440\u0443</li></ul><p>\u041F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u043C \u0447\u043B\u0435\u043D\u0430\u043C \u0442\u0430\u043A\u0436\u0435 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B:</p><ul><li>\u0421\u043A\u0438\u0434\u043A\u0438 \u043D\u0430 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435 3D-\u043F\u0440\u0438\u043D\u0442\u0435\u0440\u0430\u043C\u0438</li><li>\u0420\u0430\u0434\u0438\u043E\u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 (\u0441\u043F\u0435\u043A\u0442\u0440\u043E\u0430\u043D\u0430\u043B\u0438\u0437\u0430\u0442\u043E\u0440, SDR \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435, GSM \u0431\u0430\u0437\u043E\u0432\u044B\u0435 \u0441\u0442\u0430\u043D\u0446\u0438\u0438 \u0438 \u0442.\u0434.)</li><li>\u0412\u0441\u044F\u043A\u043E\u0435 \u0440\u0430\u0437\u043D\u043E\u0435 \u0434\u0440\u0443\u0433\u043E\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435</li><li>\u0414\u043E\u0441\u0442\u0443\u043F \u043A \u0437\u0430\u043A\u0440\u044B\u0442\u044B\u043C \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F\u043C</li></ul><p><img src="http://neuronspace.ru/wp/wp-content/uploads/2013/03/650x468xsoldering-650x468.jpg.pagespeed.ic.1-WQnZtW_e.webp" alt=""></p><h2 id="\u0434n\u044F-\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0445-\u0447n\u0435\u043D\u043E\u0432" tabindex="-1">\u0414\u043B\u044F \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0445 \u0447\u043B\u0435\u043D\u043E\u0432 <a class="header-anchor" href="#\u0434n\u044F-\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0445-\u0447n\u0435\u043D\u043E\u0432" aria-hidden="true">#</a></h2><p><strong>\u041F\u043E\u0441\u0435\u0442\u0438\u0442\u0435\u043B\u044C (Dynamic)</strong> \u2013 3 000 \u0440\u0443\u0431\u043B\u0435\u0439 \u0432 \u043C\u0435\u0441\u044F\u0446.</p><p>\u0414\u043E\u0441\u0442\u0443\u043F \u0432 \u0445\u0430\u043A\u0441\u043F\u0435\u0439\u0441 \u0432 \u043B\u044E\u0431\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0431\u0435\u0437 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439. \u0421\u043A\u0438\u0434\u043A\u0438 \u0438 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435, \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u0447\u043B\u0435\u043D\u043E\u0432. \u0422\u044B \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0448\u044C \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u0445\u0430\u043A\u0435\u0440\u0441\u043A\u043E\u0439 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B \u0432 \u0420\u043E\u0441\u0441\u0438\u0438.</p><p><strong>\u0420\u0435\u0437\u0438\u0434\u0435\u043D\u0442 (Static)</strong> \u2013 10 000 \u0440\u0443\u0431\u043B\u0435\u0439 \u0432 \u043C\u0435\u0441\u044F\u0446.</p><p>\u0412\u0441\u0435 \u0431\u043E\u043D\u0443\u0441\u044B dynamic \u0447\u043B\u0435\u043D\u0441\u0442\u0432\u0430, \u043F\u043B\u044E\u0441 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0438\u043C\u0435\u0442\u044C \u043B\u0438\u0447\u043D\u044B\u0439 \u0443\u0433\u043E\u043B\u043E\u043A. \u041F\u0435\u0440\u0435\u043D\u0435\u0441\u0438 \u0441\u0432\u043E\u0451 \u0440\u0430\u0431\u043E\u0447\u0435\u0435 \u043C\u0435\u0441\u0442\u043E \u0432 \u0445\u0430\u043A\u0441\u043F\u0435\u0439\u0441!</p><h2 id="\u0434n\u044F-\u0433\u043E\u0441\u0442\u0435\u0439" tabindex="-1">\u0414\u043B\u044F \u0433\u043E\u0441\u0442\u0435\u0439 <a class="header-anchor" href="#\u0434n\u044F-\u0433\u043E\u0441\u0442\u0435\u0439" aria-hidden="true">#</a></h2><p><strong>\u0413\u043E\u0441\u0442\u044C (Day pass)</strong> \u2013 500 \u0440\u0443\u0431\u043B\u0435\u0439 \u0432 \u0434\u0435\u043D\u044C.</p><p>\u0412\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u043E\u0439 \u0445\u0430\u043A\u0441\u043F\u0435\u0439\u0441\u0430 \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u043E\u0434\u043D\u043E\u0433\u043E \u0434\u043D\u044F. \u0425\u0430\u043A\u0441\u043F\u0435\u0439\u0441 \u043E\u0442\u043A\u0440\u044B\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u0433\u0434\u0430 \u0435\u0441\u0442\u044C \u043A\u0442\u043E-\u0442\u043E \u0438\u0437 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0445 \u0447\u043B\u0435\u043D\u043E\u0432, \u0438 \u0447\u0442\u043E\u0431\u044B \u043D\u0435 \u043E\u043A\u0430\u0437\u0430\u0442\u044C\u0441\u044F \u043F\u0435\u0440\u0435\u0434 \u0437\u0430\u043A\u0440\u044B\u0442\u043E\u0439 \u0434\u0432\u0435\u0440\u044C\u044E, \u043B\u0443\u0447\u0448\u0435 \u0437\u0430\u0440\u0430\u043D\u0435\u0435 \u043D\u0430\u043F\u0438\u0441\u0430\u0442\u044C \u043D\u0430 <a href="mailto:neuron@hackspace.ru">neuron@hackspace.ru</a>.</p><h2 id="\u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F" tabindex="-1">\u041C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F <a class="header-anchor" href="#\u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F" aria-hidden="true">#</a></h2><p>\u0425\u0430\u043A\u0441\u043F\u0435\u0439\u0441 Neuron \u2013 \u044D\u0442\u043E \u0438\u0434\u0435\u0430\u043B\u044C\u043D\u043E\u0435 \u043C\u0435\u0441\u0442\u043E \u0434\u043B\u044F \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0441\u0435\u043C\u0438\u043D\u0430\u0440\u043E\u0432, meetup\u2019\u043E\u0432 \u0438 \u043C\u0438\u043D\u0438-\u043A\u043E\u043D\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0439 \u043F\u043E \u043B\u044E\u0431\u044B\u043C <strong>\u0433\u0438\u043A\u043E\u0432\u0441\u043A\u0438\u043C, \u0445\u0430\u043A\u0435\u0440\u0441\u043A\u0438\u043C \u0438 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C \u043E\u043A\u043E\u043B\u043E\u0430\u0439\u0442\u0438\u0448\u043D\u043E\u0439 \u0430\u0443\u0434\u0438\u0442\u043E\u0440\u0438\u0438 \u0442\u0435\u043C\u0430\u043C (\u0432\u0430\u0436\u043D\u0430\xA0\u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430)</strong>. \u0415\u0441\u043B\u0438 \u0432\u0430\u043C \u043D\u0435 \u0445\u043E\u0447\u0435\u0442\u0441\u044F \u0434\u0435\u043B\u0430\u0442\u044C \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0432 \u043A\u0430\u0444\u0435 \u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0438\u0442\u044C \u043A\u0430\u043A\u0443\u044E-\u043D\u0438\u0431\u0443\u0434\u044C \u043A\u043E\u043C\u043F\u0430\u043D\u0438\u044E \u0432\u0430\u0441 \u043F\u0440\u0438\u044E\u0442\u0438\u0442\u044C \u2013 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442\u0435 \u043A \u043D\u0430\u043C. \u041C\u044B \u043D\u0435 \u0431\u0443\u0434\u0435\u043C \u043D\u0430\u043A\u043B\u0430\u0434\u044B\u0432\u0430\u0442\u044C \u043D\u0430 \u0432\u0430\u0448\u0435 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u043A\u043E\u0440\u043F\u043E\u0440\u0430\u0442\u0438\u0432\u043D\u044B\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u0438 \u0443\u0442\u0440\u0443\u0436\u0434\u0430\u0442\u044C \u043F\u0440\u043E\u0447\u0438\u043C\u0438 \u0433\u043B\u0443\u043F\u043E\u0441\u0442\u044F\u043C\u0438.</p><p>\u041C\u044B \u0440\u0430\u0434\u044B \u0445\u043E\u0441\u0442\u0438\u0442\u044C \u043A\u0430\u043A \u043F\u043B\u0430\u0442\u043D\u044B\u0435, \u0442\u0430\u043A \u0438 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0435 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F.</p><p>\u041F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u0432\u043C\u0435\u0449\u0430\u0435\u0442:</p><ul><li><strong>\u043E\u043A\u043E\u043B\u043E 20 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0432 \u0444\u043E\u0440\u043C\u0430\u0442\u0435 \u0432\u043E\u0440\u043A\u0448\u043E\u043F\u0430,</strong></li><li><strong>\u043E\u043A\u043E\u043B\u043E 40 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0432 \u0444\u043E\u0440\u043C\u0430\u0442\u0435 \u043B\u0435\u043A\u0446\u0438\u0438.</strong></li></ul><p>\u0412\u043E \u0432\u0440\u0435\u043C\u044F \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0439 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B:</p><ul><li>\u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442 (WiFi, Ethernet)</li><li>\u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0440 (VGA, 800\u0445600)</li><li>2 \u0431\u0435\u0441\u043F\u0440\u043E\u0432\u043E\u0434\u043D\u044B\u0445 \u043C\u0438\u043A\u0440\u043E\u0444\u043E\u043D\u0430 (2.5\u2033 \u0438\u043B\u0438 3.5\u2033 jack)</li><li>\u0434\u0438\u043D\u0430\u043C\u0438\u043A\u0438\xA0(3.5\u2033 jack)</li><li>\u0432\u0451\u0431-\u043A\u0430\u043C\u0435\u0440\u0430 \u043D\u0430 \u0448\u0442\u0430\u0442\u0438\u0432\u0435 (HD, USB)</li></ul><p><a href="https://habr.com/ru/company/neuronspace/blog/494128/" class="external-link" target="_blank" rel="noopener noreferrer">\u0421\u0442\u0430\u0442\u044C\u044F \u043F\u0440\u043E \u041D\u0435\u0439\u0440\u043E\u043D \u043D\u0430 \u0425\u0430\u0431\u0440\u0435</a><a href="https://xakep.ru/2012/10/26/hack-space-neuron/" class="external-link" target="_blank" rel="noopener noreferrer">\u0421\u0442\u0430\u0442\u044C\u044F \u043D\u0430 Xakep.ru</a><a href="https://te-st.ru/2014/08/06/hakspeys-neuron-russia/" class="external-link" target="_blank" rel="noopener noreferrer">\u0421\u0442\u0430\u0442\u044C\u044F \u0432 \u0422\u0435\u043F\u043B\u0438\u0446\u0435 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0445 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0439</a></p>',22),i=[l];function s(o,p,c,u,h,d){return a(),r("div",null,i)}var k=e(t,[["render",s]]);export{g as __pageData,k as default};
